#!/usr/bin/env bash
#
# nvidia-glx-workaround.sh — Prevent NVIDIA GLX/EGL from breaking Mesa
#
# On systems with both nvidia-utils and mesa installed, libglvnd loads
# libGLX_nvidia.so.0 and libEGL_nvidia.so.0 even on non-NVIDIA GPUs.
# This can poison Mesa's GLSL compiler, causing shader compilation errors.
#
# Forces Mesa for EGL/GLX via libglvnd env vars and deploys no-op stubs
# for both NVIDIA GLX and EGL libraries.
#
# Location: ~/user_scripts/gaming/nvidia-glx-workaround/nvidia-glx-workaround.sh
#
# Usage:  nvidia-glx-workaround.sh <command> [args...]
#   e.g.  nvidia-glx-workaround.sh factorio
#         nvidia-glx-workaround.sh ./start.n.sh
#
# Clean cached stubs:  nvidia-glx-workaround.sh --clean
# Print version/info:  nvidia-glx-workaround.sh --info

set -euo pipefail

STUB_DIR="${HOME}/.cache/nvidia-glx-workaround"
STUB_64_DIR="$STUB_DIR/64"

# Embedded 64-bit stub (pre-compiled, no gcc needed)
STUB_BASE64=""

# Embedded 64-bit EGL stub (pre-compiled, no gcc needed)
EGL_BASE64=""

deploy_stubs() {
    local dir="$1"
    mkdir -p "$dir"
    echo "$STUB_BASE64" | base64 -d > "$dir/libGLX_nvidia.so.0" 2>/dev/null
    echo "$EGL_BASE64" | base64 -d > "$dir/libEGL_nvidia.so.0" 2>/dev/null
    chmod 644 "$dir/libGLX_nvidia.so.0" "$dir/libEGL_nvidia.so.0"
}

# Handle special commands
case "${1:-}" in
    --clean|-c)
        rm -rf "$STUB_DIR"
        echo "Cleaned stubs: $STUB_DIR"
        exit 0
        ;;
    --info|-i)
        echo "nvidia-glx-workaround.sh"
        echo "Stub dir: $STUB_DIR"
        for pair in "64/libGLX_nvidia.so.0" "64/libEGL_nvidia.so.0"; do
            f="$STUB_DIR/$pair"
            [ -f "$f" ] && echo "  $pair: $(stat -c%s "$f") bytes" \
                    || echo "  $pair: not deployed"
        done
        if [ -f /usr/lib/libGLX_nvidia.so.0 ] || [ -f /usr/lib/libEGL_nvidia.so.0 ]; then
            echo "NVIDIA GLX/EGL detected: yes"
        else
            echo "NVIDIA GLX/EGL detected: no (workaround not needed)"
        fi
        exit 0
        ;;
esac

if [ "$#" -eq 0 ]; then
    echo "Usage: $(basename "$0") <command> [args...]" >&2
    exit 1
fi

# 1. Force Mesa via libglvnd environment variables
export __GLX_VENDOR_LIBRARY_NAME="mesa"

if [ -f /usr/share/glvnd/egl_vendor.d/50_mesa.json ]; then
    export __EGL_VENDOR_LIBRARY_FILENAMES="/usr/share/glvnd/egl_vendor.d/50_mesa.json"
fi

export __NV_PRIME_RENDER_OFFLOAD=0

# 2. Deploy stubs only if NVIDIA libraries are installed
HAS_NVIDIA=""
[ -f /usr/lib/libGLX_nvidia.so.0 ] || [ -f /usr/lib/libEGL_nvidia.so.0 ] && HAS_NVIDIA=1

if [ -n "$HAS_NVIDIA" ]; then
    # Deploy 64-bit stubs if missing
    if [ ! -f "$STUB_64_DIR/libGLX_nvidia.so.0" ]; then
        deploy_stubs "$STUB_64_DIR"
    fi

    # 3. Set library path to intercept NVIDIA GLX/EGL
    STUB_PATH="$STUB_64_DIR"

    if [ -n "$STUB_PATH" ]; then
        export LD_LIBRARY_PATH="$STUB_PATH${LD_LIBRARY_PATH:+:$LD_LIBRARY_PATH}"
    fi
fi

exec "$@"
